CREATE TABLE [tblPlay](	[ID] [INTEGER], [ThemeName] [int] NULL, [StartDate] [nvarchar](50) NULL, [StartTime] [nvarchar](50) NULL, [StartUTCDateTime] [nvarchar](50) NULL, [EndUTCDateTime] [nvarchar](50) NULL, [ShootingNumber] [int] NULL, [StreakLevel] [int] NULL, [ShootingMode] [nvarchar](10) NULL, [Width] [int] NULL, [Height] [int] NULL, [Fps] [int] NULL, [FilePath] [nvarchar](30) NULL, [MovieMode] [nvarchar](10) NULL, CONSTRAINT [PK_tblPlay] PRIMARY KEY([ID]));
